// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IERC20 {
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function transfer(address to, uint256 amount) external returns (bool);
}

contract MockDEX {
    IERC20 public token;

    constructor(address _token) {
        token = IERC20(_token);
    }

    function pullTokens(uint256 amount) external {
        require(token.transferFrom(msg.sender, address(this), amount), "Transfer failed");
    }

    function swapMonForToken() external payable {
        require(msg.value > 0, "Must send MON");
        uint256 tokenAmount = msg.value; // 1:1 price
        require(token.transfer(msg.sender, tokenAmount), "Token transfer failed");
    }
}

contracts/MockToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract MockToken {
    string public name = "Gas Money Token";
    string public symbol = "GMT";
    uint8 public decimals = 18;
    uint256 public totalSupply;

    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    function mint(address to, uint256 amount) external {
        balanceOf[to] += amount;
        totalSupply += amount;
        emit Transfer(address(0), to, amount);
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        allowance[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

    function transfer(address to, uint256 amount) external returns (bool) {
        require(balanceOf[msg.sender] >= amount, "Insufficient balance");
        balanceOf[msg.sender] -= amount;
        balanceOf[to] += amount;
        emit Transfer(msg.sender, to, amount);
        return true;
    }

    function transferFrom(address from, address to, uint256 amount) external returns (bool) {
        require(allowance[from][msg.sender] >= amount, "Insufficient allowance");
        require(balanceOf[from] >= amount, "Insufficient balance");
        allowance[from][msg.sender] -= amount;
        balanceOf[from] -= amount;
        balanceOf[to] += amount;
        emit Transfer(from, to, amount);
        return true;
    }
}

contracts/QuestBadges.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract QuestBadges {
    mapping(address => mapping(uint8 => bool)) public completed;
    event QuestCompleted(address indexed user, uint8 indexed questId, uint256 timestamp);

    function completeQuest(uint8 questId) external {
        require(!completed[msg.sender][questId], "Already completed");
        completed[msg.sender][questId] = true;
        emit QuestCompleted(msg.sender, questId, block.timestamp);
    }

    function hasCompleted(address user, uint8 questId) external view returns (bool) {
        return completed[user][questId];
    }
}

